const path = require('path');

// Função para tentar recuperar acentos quebrados
function fixEncoding(str) {
  if (!str) return str;

  try {
    // Converte UTF-8 mal interpretado em Latin1 → UTF8 correto
    return Buffer.from(str, 'binary').toString('utf8');
  } catch {
    return str;
  }
}

// Função de normalização de caminho
function normalize(p) {
  if (!p) return '';
  let txt = fixEncoding(p);
  return txt.replace(/\\\\/g, '\\').replace(/\/+$/, '').trim();
}

