const entradas = $input.all().map(r => r.json);

// separa paths (com id) e origins (arquivos)
const dirs = entradas.filter(e => e.path && e.id);
const origins = entradas.filter(e => e.origin);

// função para normalizar strings e corrigir acentos
const norm = (s) =>
  s.normalize("NFD")
   .replace(/[\u0300-\u036f]/g, "")
   .replace(/\\/g, "/")
   .toLowerCase();

// concilia
const resultado = origins.map(o => {
  const origemNorm = norm(o.origin);

  // tenta montar path relativo a partir do padrão após "MDG-ACG-DG"
  let rel = origemNorm.split("mdg-acg-dg/")[1] || "";

  // remove o nome do arquivo, deixando só pastas
  const partes = rel.split("/");
  partes.pop(); // remove filename
  rel = partes.join("/");

  // procura o match mais longo possível no array dirs
  let match = null;
  let maior = 0;

  for (const d of dirs) {
    const p = norm(d.path);
    if (rel.startsWith(p) && p.length > maior) {
      maior = p.length;
      match = d;
    }
  }

  return {
    origin: o.origin,
    pathBase: match ? match.path : null,
    id: match ? match.id : null,
    file: o.origin.split("\\").pop()
  };
});

return resultado.map(r => ({ json: r }));

// Função que tenta corrigir caracteres quebrados tipo "�"
function fixEncoding(str) {
  if (!str) return str;

  // 1. Se já está normal, retorna
  if (!str.includes("�")) return str;

  // 2. Tenta recodificar interpretando como Windows-1252
  try {
    const buf = Buffer.from(str, 'binary');
    const recoded = buf.toString('utf8');
    if (!recoded.includes("�")) return recoded;
  } catch {}

  // 3. Fallback: substitui manualmente padrões comuns quebrados
  const map = {
    "MAR�O": "MARÇO",
    "FEVEREIR�": "FEVEREIRO",
    "JANEIR�": "JANEIRO",
    "ABR�": "ABRIL",
    "MAI�": "MAIO",
    "JUNH�": "JUNHO",
    "JULH�": "JULHO",
    "AGOST�": "AGOSTO",
    "SETEMBR�": "SETEMBRO",
    "OUTUBR�": "OUTUBRO",
    "NOVEMBR�": "NOVEMBRO",
    "DEZEMBR�": "DEZEMBRO"
  };

  let fixed = str;
  for (const bad in map) {
    fixed = fixed.replace(bad, map[bad]);
  }

  // 4. Remove caracteres impossíveis
  return fixed.replace(/�/g, "");
}


