"const fs = require('fs');
const path = require('path');

// Entrada do agente
const base64 = $fromAI('data', 'base64', 'string');
const filename = $fromAI('data', 'filename', 'string');

if (!base64) {
  throw new Error('Nenhum dado base64 recebido do agente.');
}
if (!filename) {
  throw new Error('Nenhum nome de arquivo recebido.');
}

// Gera caminho temporário
const tmpPath = `/tmp/${filename}`;

// Converte base64 → Buffer
const buffer = Buffer.from(base64, 'base64');

// Salva arquivo binário
fs.writeFileSync(tmpPath, buffer);

return {
  binary: {
    data: {
      data: buffer,
      fileName: filename,
      mimeType: 'application/octet-stream'
    }
  }
};"
